INSERT INTO nex_site.jobs VALUES ('6eb63a79-9fc8-4aec-bdea-80d2c61b700b', 'Senior Cloud Architect', 'Engineering', 'Bangkok / Remote', 'full-time', '80,000 – 130,000 บาท', 'ออกแบบและวางโครงสร้าง Cloud Infrastructure บน AWS / Azure / GCP ให้กับลูกค้าองค์กรชั้นนำ', '["ออกแบบ Cloud Architecture ให้ตรงกับความต้องการทางธุรกิจ", "ดูแล High Availability และ Disaster Recovery", "ให้คำแนะนำทีม Engineering ด้าน Best Practices", "ประสานงานกับลูกค้าเพื่อวางแผน Cloud Migration"]', '["ประสบการณ์ 5+ ปี ด้าน Cloud (AWS/Azure/GCP)", "มี Cloud Certification (Solutions Architect, Professional)", "เชี่ยวชาญ Terraform, Kubernetes, Docker", "สามารถสื่อสารภาษาอังกฤษได้ในระดับดี"]', '["ประกันสุขภาพ", "Flexible Hours", "Work From Home", "Training Budget", "Stock Option"]', '["AWS", "Azure", "GCP", "Terraform", "Kubernetes"]', 'open', 0, '2026-03-31 00:00:00', '2026-02-23 16:02:45.624805', '2026-02-23 16:02:45.624805');
INSERT INTO nex_site.jobs VALUES ('0a0439a3-2c43-49ef-b9ea-a67305385e3f', 'AI/ML Engineer', 'Engineering', 'Bangkok', 'full-time', '70,000 – 110,000 บาท', 'พัฒนาระบบ AI/Machine Learning เพื่อสร้าง Business Value ให้กับองค์กรในหลากหลายอุตสาหกรรม', '["พัฒนาและ Deploy ML Models ใน Production", "ทำ Data Pipeline และ Feature Engineering", "ร่วมมือกับทีม Product และลูกค้าในการกำหนด AI Strategy"]', '["ปริญญาตรีขึ้นไปด้าน Computer Science, Data Science หรือสาขาที่เกี่ยวข้อง", "ชำนาญ Python, TensorFlow, PyTorch", "ประสบการณ์ MLOps จะได้รับการพิจารณาเป็นพิเศษ"]', '["ประกันสุขภาพ", "Flexible Hours", "Training Budget", "Conference Allowance"]', '["Python", "Machine Learning", "TensorFlow", "MLOps", "Data Science"]', 'open', 0, '2026-04-15 00:00:00', '2026-02-23 16:02:45.739598', '2026-02-23 16:02:45.739598');
INSERT INTO nex_site.jobs VALUES ('5c1e05ce-785d-4533-9386-c9a65eefeec4', 'Full-Stack Developer (React / Node.js)', 'Engineering', 'Bangkok / Hybrid', 'full-time', '50,000 – 80,000 บาท', 'พัฒนาเว็บแอปพลิเคชันสมัยใหม่ด้วย TypeScript, React, Next.js และ NestJS', '["พัฒนา Frontend ด้วย React / Next.js", "ออกแบบ REST API ด้วย Node.js / NestJS", "เขียน Unit Test และ Integration Test"]', '["ประสบการณ์ 3+ ปีด้าน Full-Stack Development", "ชำนาญ TypeScript, React, Node.js", "รู้จัก PostgreSQL, Redis"]', '["ประกันสุขภาพ", "Work From Home", "Training Budget"]', '["React", "Next.js", "TypeScript", "Node.js", "PostgreSQL"]', 'open', 0, '2026-04-30 00:00:00', '2026-02-23 16:02:45.749013', '2026-02-23 16:02:45.749013');
INSERT INTO nex_site.jobs VALUES ('aa830eeb-ce35-4cb2-b9cb-a22718c6e6d3', 'IT Sales Executive', 'Sales', 'Bangkok', 'full-time', '35,000 – 60,000 บาท + Commission', 'นำเสนอและขายโซลูชัน Cloud & IT Services ให้กับองค์กรขนาดกลางและขนาดใหญ่', '["หาลูกค้าใหม่และรักษาความสัมพันธ์กับลูกค้าเดิม", "นำเสนอ Solution ที่ตรงกับความต้องการ", "จัดทำ Proposal และ Quotation"]', '["ประสบการณ์ด้าน IT Sales 2+ ปี", "มีเครือข่าย Corporate Clients", "สื่อสารภาษาอังกฤษได้ดี"]', '["Commission ไม่จำกัด", "Car Allowance", "ประกันสุขภาพ", "โบนัส"]', '["Sales", "B2B", "Cloud", "CRM", "Presentation"]', 'open', 0, '2026-05-31 00:00:00', '2026-02-23 16:02:45.757079', '2026-02-23 16:02:45.757079');
INSERT INTO nex_site.jobs VALUES ('5102b685-94b4-4a33-869f-497577fcbf60', 'Digital Marketing Specialist', 'Marketing', 'Bangkok / Remote', 'full-time', '35,000 – 55,000 บาท', 'วางแผนและบริหารกลยุทธ์ Digital Marketing เพื่อสร้าง Brand Awareness และ Lead Generation', '["วางแผน Content Strategy และ SEO/SEM", "บริหารงบโฆษณา Google Ads, Meta Ads", "วิเคราะห์ข้อมูลและรายงานผล"]', '["ประสบการณ์ 2+ ปีด้าน Digital Marketing", "ชำนาญ Google Analytics, SEO Tools", "มีความคิดสร้างสรรค์"]', '["Flexible Hours", "Remote Work", "Training Budget"]', '["SEO", "SEM", "Content Marketing", "Google Analytics", "Social Media"]', 'open', 0, NULL, '2026-02-23 16:02:45.765243', '2026-02-23 16:02:45.765243');
INSERT INTO nex_site.jobs VALUES ('d7a16b7b-0cc7-48b7-973c-70384f17b9e5', 'UX/UI Designer', 'Design', 'Bangkok / Hybrid', 'full-time', '40,000 – 65,000 บาท', 'ออกแบบ User Experience และ Interface สำหรับ Web Application และ Mobile App', '["ทำ User Research และ Usability Testing", "ออกแบบ Wireframe, Prototype ด้วย Figma", "ทำงานร่วมกับ Development Team"]', '["Portfolio แสดงผลงานที่ดี", "ชำนาญ Figma, Adobe XD", "เข้าใจ Design System"]', '["Creative Environment", "Training Budget", "Work From Home"]', '["Figma", "UX", "UI", "Prototyping", "User Research"]', 'open', 0, NULL, '2026-02-23 16:02:45.776001', '2026-02-23 16:02:45.776001');
INSERT INTO nex_site.jobs VALUES ('18d8522d-26ba-4b57-824f-f5a8d747027d', 'Software Engineer Internship', 'Engineering', 'Bangkok', 'internship', '15,000 บาท', 'โอกาสสำหรับนิสิตนักศึกษาที่ต้องการเรียนรู้การพัฒนาซอฟต์แวร์ในสภาพแวดล้อมจริง', '["ช่วย Develop Feature ในโปรเจกต์จริง", "เขียน Unit Test", "เข้าร่วม Code Review"]', '["กำลังศึกษาสาขา CS, SE, IT หรือที่เกี่ยวข้อง", "รู้พื้นฐาน Programming อย่างน้อย 1 ภาษา", "มีความกระตือรือร้นและอยากเรียนรู้"]', '["Mentoring", "Real Project Experience", "Certificate"]', '["Internship", "JavaScript", "React", "Learning"]', 'open', 0, '2026-03-15 00:00:00', '2026-02-23 16:02:45.784838', '2026-02-23 16:02:45.784838');
